import jsPDF from 'jspdf';

const PAGE_W      = 210;
const PAGE_H      = 297;
const MARGIN_X    = 20;
const MARGIN_TOP  = 18;
const MARGIN_BOT  = 18;
const CONTENT_W   = PAGE_W - MARGIN_X * 2;

export function exportToPDF(docData, filename = 'assessment-sheet') {
  const {
    tpl, studentName, uid, section,
    worksheetNo, datePerf, sectionContent,
    outputImages = [],
  } = docData;

  const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  const BASE   = tpl.fontSize  || 12;
  const H1     = BASE + 4;
  const H2     = BASE + 1;
  const SMALL  = BASE - 1;
  const LINE_H = BASE * 0.45 * (tpl.spacing || 1.6);

  let y = MARGIN_TOP;

  const checkPage = (needed = LINE_H) => {
    if (y + needed > PAGE_H - MARGIN_BOT) {
      pdf.addPage();
      y = MARGIN_TOP;
    }
  };

  const writeText = (text, x, maxW, lineH, align = 'left') => {
    if (!text) return;
    const lines = pdf.splitTextToSize(String(text), maxW);
    lines.forEach(line => {
      checkPage(lineH);
      pdf.text(line, align === 'center' ? PAGE_W / 2 : x, y, { align });
      y += lineH;
    });
  };

  // ═════════ CU DEPARTMENT HEADER ═════════
  const LOGO_SIZE = 18;
  const logoX = MARGIN_X;
  const logoY = y;

  // Logo box
  pdf.setDrawColor(30, 30, 30);
  pdf.setFillColor(26, 26, 26);
  pdf.setLineWidth(0.5);
  pdf.rect(logoX, logoY, LOGO_SIZE, LOGO_SIZE, 'FD');

  // CU text inside logo
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(11);
  pdf.setTextColor(255, 255, 255);
  pdf.text('CU', logoX + LOGO_SIZE / 2, logoY + LOGO_SIZE / 2 - 1, { align: 'center' });
  pdf.setFontSize(3.5);
  pdf.text('CHANDIGARH', logoX + LOGO_SIZE / 2, logoY + LOGO_SIZE / 2 + 3, { align: 'center' });
  pdf.text('UNIVERSITY', logoX + LOGO_SIZE / 2, logoY + LOGO_SIZE / 2 + 5, { align: 'center' });

  // Department text (right of logo)
  const textX   = logoX + LOGO_SIZE + 5;
  const textMaxW = CONTENT_W - LOGO_SIZE - 5;

  pdf.setFont('times', 'bold');
  pdf.setFontSize(9);
  pdf.setTextColor(180, 0, 0);
  pdf.text('DEPARTMENT OF', textX, logoY + 4.5);

  pdf.setFont('times', 'bold');
  pdf.setFontSize(15);
  pdf.setTextColor(10, 10, 10);
  const deptLines = pdf.splitTextToSize('COMPUTER SCIENCE & ENGINEERING', textMaxW);
  deptLines.forEach((line, idx) => {
    pdf.text(line, textX, logoY + 10 + idx * 7);
  });

  // Tagline below logo
  pdf.setFont('times', 'italic');
  pdf.setFontSize(SMALL - 1);
  pdf.setTextColor(80, 80, 80);
  pdf.text('Discover. Learn. Empower.', logoX, logoY + LOGO_SIZE + 4);

  // Horizontal rule under header
  y = logoY + LOGO_SIZE + 8;
  pdf.setDrawColor(80, 80, 80);
  pdf.setLineWidth(0.5);
  pdf.line(MARGIN_X, y, PAGE_W - MARGIN_X, y);
  y += 10;

  // ═════════ WORKSHEET TITLE ═════════
  pdf.setFont('times', 'bold');
  pdf.setFontSize(H1);
  pdf.setTextColor(10, 10, 10);
  writeText(`Worksheet ${worksheetNo}`, MARGIN_X, CONTENT_W, LINE_H * 1.4, 'center');
  y += 3;

  // ═════════ STUDENT INFO ═════════
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(BASE);

  const infoRows = [
    [['Student Name', studentName],  ['UID', uid]],
    [['Branch', tpl.branch],         ['Section/Group', section]],
    [['Semester', tpl.semester],     ['Date of Performance', datePerf]],
    [['Subject Name', tpl.subject],  ['Subject Code', tpl.subjectCode]],
  ];

  const colW = CONTENT_W / 2;
  const rowH = LINE_H * 1.2;

  infoRows.forEach(row => {
    checkPage(rowH);
    row.forEach(([label, value], ci) => {
      const x = MARGIN_X + ci * colW;
      pdf.setFont('helvetica', 'bold');
      pdf.text(`${label}: `, x, y);
      const labelW = pdf.getTextWidth(`${label}: `);
      pdf.setFont('helvetica', 'normal');
      pdf.text(String(value || ''), x + labelW, y);
    });
    y += rowH;
  });

  y += 4;

  // ═════════ SECTIONS ═════════
  tpl.sections.forEach((sec, i) => {
    checkPage(LINE_H * 2);

    // Section heading
    pdf.setFont('times', 'bold');
    pdf.setFontSize(H2);
    pdf.setTextColor(10, 10, 10);
    writeText(`${i + 1}. ${sec}:`, MARGIN_X, CONTENT_W, LINE_H * 1.3);
    y += 2;

    const content  = sectionContent[sec] || '';
    const isCode   = sec.toLowerCase().includes('code');
    const isOutput = sec.toLowerCase() === 'output';

    if (isCode && content) {
      // Code block — monospace style
      pdf.setFont('courier', 'normal');
      pdf.setFontSize(BASE - 1);
      pdf.setTextColor(20, 20, 20);
      y += 2;
      const codeLines = pdf.splitTextToSize(content, CONTENT_W - 8);
      codeLines.forEach(line => {
        checkPage(LINE_H);
        pdf.text(line, MARGIN_X + 4, y);
        y += LINE_H;
      });
      y += 2;

    } else if (isOutput && outputImages.length > 0) {
      // Output section: text first, then images
      if (content) {
        pdf.setFont('helvetica', 'normal');
        pdf.setFontSize(BASE);
        pdf.setTextColor(30, 30, 30);
        writeText(content, MARGIN_X + 2, CONTENT_W - 4, LINE_H);
      }

      // Embed each output image
      outputImages.forEach((img, idx) => {
        try {
          if (!img.dataUrl) return;

          const format = img.dataUrl.startsWith('data:image/png') ? 'PNG' : 'JPEG';
          const tmpImg = new Image();
          tmpImg.src = img.dataUrl;

          const MAX_W = CONTENT_W;
          const MAX_H = 75;
          let imgW = MAX_W;
          let imgH = MAX_H;

          if (tmpImg.naturalWidth && tmpImg.naturalHeight) {
            const ratio = tmpImg.naturalWidth / tmpImg.naturalHeight;
            imgW = Math.min(MAX_W, MAX_H * ratio);
            imgH = imgW / ratio;
            if (imgH > MAX_H) { imgH = MAX_H; imgW = imgH * ratio; }
          }

          checkPage(imgH + 12);

          const imgX = MARGIN_X + (CONTENT_W - imgW) / 2;
          pdf.addImage(img.dataUrl, format, imgX, y, imgW, imgH);
          y += imgH + 3;

          // Caption
          pdf.setFont('times', 'italic');
          pdf.setFontSize(SMALL - 1);
          pdf.setTextColor(100, 100, 100);
          const caption = `Fig ${idx + 1}: ${img.name ? img.name.replace(/\.[^.]+$/, '') : `Output ${idx + 1}`}`;
          pdf.text(caption, PAGE_W / 2, y, { align: 'center' });
          y += LINE_H + 3;
        } catch (err) {
          console.warn('Could not embed image:', err);
        }
      });

    } else {
      // Regular text section
      pdf.setFont('helvetica', 'normal');
      pdf.setFontSize(BASE);
      pdf.setTextColor(30, 30, 30);
      const align = tpl.align === 'center' ? 'center' : 'left';
      writeText(content || '(no content)', MARGIN_X + 2, CONTENT_W - 4, LINE_H, align);
    }

    y += 3;
  });

  // ═════════ PAGE NUMBERS ═════════
  const totalPages = pdf.getNumberOfPages();
  for (let p = 1; p <= totalPages; p++) {
    pdf.setPage(p);
    pdf.setFontSize(9);
    pdf.setTextColor(150, 150, 150);
    pdf.text(`Page ${p} of ${totalPages}`, PAGE_W / 2, PAGE_H - 7, { align: 'center' });
  }

  pdf.save(`${filename}.pdf`);
}
